1	export type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	export type Damage = { itemType: string; amount: number };
3	export type Incident = { cause: string; damages: Damage[] };
4	export type QuoteStep = { op: "quote"; items: Item[] };
5	export type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	export type Step = QuoteStep | ClaimStep;
7	export type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
8	export type QuoteResult = { premium: number };
9	export type ClaimResult = { payout: number; remainingCap: number };
10	export type ScenarioResult = { results: Array<QuoteResult | ClaimResult> };
11	
12	const PROCESSING_FEE = 5;
13	const FIRST_INSURANCE_RATE = 0.1;
14	const CURSE_SURCHARGE_RATE = 0.5;
15	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
16	const HIGH_ENCHANTMENT_THRESHOLD = 5;
17	const LOYALTY_DISCOUNT_RATE = 0.2;
18	const LOYALTY_THRESHOLD_YEARS = 2;
19	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
20	const DEDUCTIBLE = 100;
21	const CAP_MULTIPLIER = 2;
22	
23	type Customer = { yearsWithMHPCO: number };
24	const COMPONENT_UNIT_BASE = 25;
25	const COMPONENT_BLOCK_SIZE = 3;
26	const COMPONENT_BLOCK_BASE = 60;
27	
28	const MAIN_ITEM_BASE_PREMIUM: Record<string, number> = {
29	  sword: 100,
30	  amulet: 60,
31	  staff: 80,
32	  potion: 40,
33	};
34	
35	const ITEM_INSURANCE_VALUE: Record<string, number> = {
36	  sword: 1000,
37	  amulet: 600,
38	  staff: 800,
39	  potion: 400,
40	  rune: 250,
41	  moonstone: 250,
42	};
43	
44	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
45	
46	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
47	
48	type BillingGroup = { base: number; cursed: boolean; enchantment: number };
49	
50	const componentBundleBase = (count: number): number => {
51	  if (count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_BASE;
52	  return count * COMPONENT_UNIT_BASE;
53	};
54	
55	const billingGroups = (items: Item[]): BillingGroup[] => {
56	  const groups: BillingGroup[] = [];
57	  const componentCounts = new Map<string, number>();
58	  for (const item of items) {
59	    if (isComponent(item)) {
60	      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
61	    } else {
62	      groups.push({
63	        base: MAIN_ITEM_BASE_PREMIUM[item.type],
64	        cursed: item.cursed === true,
65	        enchantment: item.enchantment ?? 0,
66	      });
67	    }
68	  }
69	  for (const count of componentCounts.values()) {
70	    groups.push({ base: componentBundleBase(count), cursed: false, enchantment: 0 });
71	  }
72	  return groups;
73	};
74	
75	const groupPremium = ({ base, cursed, enchantment }: BillingGroup): number => {
76	  const curseSurcharge = cursed ? base * CURSE_SURCHARGE_RATE : 0;
77	  const enchantmentSurcharge =
78	    enchantment >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
79	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
80	  return base + curseSurcharge + enchantmentSurcharge + firstInsuranceSurcharge;
81	};
82	
83	const sumGroupPremiums = (groups: BillingGroup[]): number =>
84	  groups.reduce((sum, g) => sum + groupPremium(g), 0);
85	
86	const policyBaseOf = (groups: BillingGroup[]): number =>
87	  groups.reduce((sum, g) => sum + g.base, 0);
88	
89	const loyaltyDiscountOf = (policyBase: number, customer: Customer): number =>
90	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
91	
92	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
93	  const groups = billingGroups(items);
94	  const itemsTotal = sumGroupPremiums(groups);
95	  const policyBase = policyBaseOf(groups);
96	  const loyaltyDiscount = loyaltyDiscountOf(policyBase, customer);
97	  const followUpDiscount = isFollowUp ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
98	  return Math.ceil(itemsTotal - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
99	};
100	
101	type Policy = { items: Item[]; cap: number };
102	
103	const insuranceSumOf = (items: Item[]): number =>
104	  items.reduce((sum, item) => sum + ITEM_INSURANCE_VALUE[item.type], 0);
105	
106	const damagePayout = (damage: Damage): number => Math.max(0, damage.amount - DEDUCTIBLE);
107	
108	const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
109	  const totalDamage = incident.damages.reduce((sum, d) => sum + damagePayout(d), 0);
110	  const payout = Math.min(totalDamage, policy.cap);
111	  policy.cap -= payout;
112	  return { payout: Math.floor(payout), remainingCap: Math.floor(policy.cap) };
113	};
114	
115	export const runScenario = (scenario: Scenario): ScenarioResult => {
116	  const policies: Policy[] = [];
117	  let quoteCount = 0;
118	  const results: Array<QuoteResult | ClaimResult> = scenario.steps.map((step) => {
119	    if (step.op === "quote") {
120	      const isFollowUp = quoteCount > 0;
121	      quoteCount += 1;
122	      policies.push({
123	        items: step.items,
124	        cap: insuranceSumOf(step.items) * CAP_MULTIPLIER,
125	      });
126	      return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
127	    }
128	    return processClaim(policies[step.policy], step.incident);
129	  });
130	  return { results };
131	};
